// Optimization Strategy for 10K+ Concurrent Streams
fn tune_stream(stream: &TcpStream) -> Result<()> {
// 1. Optimize memory density (Reduce from 128KB to 64KB)
stream.set_recv_buffer_size(64 * 1024)?;
stream.set_send_buffer_size(64 * 1024)?;

fn tune_listener(listener: &TcpListener) -> Result<()> {
// 3. Bind with SO_REUSEADDR for faster restarts
listener.set_reuseaddr(true)?;
Ok(())
}
